package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.returning.*;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.domain.returning.SupplierReturnAggregate;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;import java.util.List;
@RestController @RequestMapping("/api/supplier/v1/returns") public class SupplierReturnController{private final SupplierReturnApplicationService service;private final CommandContextFactory contexts;public SupplierReturnController(SupplierReturnApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@GetMapping public ApiResponse<PageResult<SupplierReturnView>> page(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.page(supplierId,scope(jwt),status,pageNo,pageSize),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@GetMapping("/{id}")public ApiResponse<SupplierReturnView> detail(@PathVariable long id,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.detail(id,scope(jwt)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@PostMapping public ApiResponse<CommandResult> create(@Valid @RequestBody Create b,HttpServletRequest r,Authentication a){return ok(service.create(b.supplierId(),b.warehouseId(),b.qualityIssueId(),b.reason(),b.lines().stream().map(l->new SupplierReturnAggregate.NewLine(l.skuCode(),l.batchNo(),l.inventoryStatus(),l.requestedQty())).toList(),contexts.create(r,a)),r);}@PostMapping("/{id}/submit")public ApiResponse<CommandResult> submit(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){return ok(service.submit(id,b.version(),contexts.create(r,a)),r);}@PostMapping("/{id}/review")public ApiResponse<CommandResult> review(@PathVariable long id,@Valid @RequestBody Review b,HttpServletRequest r,Authentication a){return ok(service.review(id,b.version(),b.passed(),b.comment(),contexts.create(r,a)),r);}@PostMapping("/{id}/inventory-lock")public ApiResponse<CommandResult> lock(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){return ok(service.requestInventoryLock(id,b.version(),contexts.create(r,a)),r);}@PostMapping("/{id}/supplier-confirm")public ApiResponse<CommandResult> confirm(@PathVariable long id,@Valid @RequestBody Confirm b,HttpServletRequest r,Authentication a){return ok(service.supplierConfirm(id,b.version(),b.hasDifference(),b.reason(),contexts.create(r,a)),r);}@PostMapping("/{id}/resolve-difference")public ApiResponse<CommandResult> resolve(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){return ok(service.resolveDifference(id,b.version(),contexts.create(r,a)),r);}@PostMapping("/{id}/close")public ApiResponse<CommandResult> close(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){return ok(service.close(id,b.version(),contexts.create(r,a)),r);}private ApiResponse<CommandResult> ok(CommandResult v,HttpServletRequest r){return ApiResponse.success(v,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt j){Number n=j.hasClaim("supplier_id")?j.getClaim("supplier_id"):null;return n==null?null:n.longValue();}public record Create(@Positive long supplierId,@Positive long warehouseId,Long qualityIssueId,@NotBlank String reason,@NotEmpty List<Line> lines){}public record Line(@NotBlank String skuCode,String batchNo,@NotBlank String inventoryStatus,@DecimalMin(value="0",inclusive=false)BigDecimal requestedQty){}public record Version(@PositiveOrZero int version){}public record Review(@PositiveOrZero int version,boolean passed,String comment){}public record Confirm(@PositiveOrZero int version,boolean hasDifference,String reason){}
}
